#include <stdio.h>

int main(void) {
    size_t count;
    int values[100];
    if (scanf("%zu", &count) != 1 || count == 0 || count > 100) return 1;
    for (size_t i = 0; i < count; ++i) if (scanf("%d", &values[i]) != 1) return 1;
    int maximum = values[0];
    for (size_t i = 1; i < count; ++i) if (values[i] > maximum) maximum = values[i];
    printf("%d\n", maximum);
    return 0;
}
